u_to_le32(elen);\n\t\tlad->extLocation = cpu_to_lelb(*eloc);\n\t\tmemset(lad->impUse, 0x00, sizeof(lad->impUse));\n\t\tadsize = sizeof(struct long_ad);\n\t\tbreak;\n\tdefault:\n\t\treturn;\n\t}\n\n\tif (epos->bh) {\n\t\tif (!UDF_QUERY_FLAG(inode->i_sb, UDF_FLAG_STRICT) ||\n\t\t    UDF_SB(inode->i_sb)->s_udfrev >= 0x0201) {\n\t\t\tstruct allocExtDesc *aed =\n\t\t\t\t(struct allocExtDesc *)epos->bh->b_data;\n\t\t\tudf_update_tag(epos->bh->b_data,\n\t\t\t\t       le32_to_cpu(aed->lengthAllocDescs) +\n\t\t\t\t       sizeof(struct allocExtDesc));\n\t\t}\n\t\tmark_buffer_dirty_inode(epos->bh, inode);\n\t} else {\n\t\tmark_inode_dirty(inode);\n\t}\n\n\tif (inc)\n\t\tepos->offset += adsize;\n}\n\n/*\n * Only 1 indirect extent in a row really makes sense but allow upto 16 in case\n * someone does some weird stuff.\n */\n#define UDF_MAX_INDIR_EXTS 16\n\n/*\n * Returns 1 on success, -errno on error, 0 on hit EOF.\n */\nint udf_next_aext(struct inode *inode, struct extent_position *epos,\n\t\t  struct kernel_lb_addr *eloc, uint32_t *elen, int8_t *etype,\n\t\t  int inc)\n{\n\tunsigned int indirections = 0;\n\tint ret = 0;\n\tudf_pblk_t block;\n\n\twhile (1) {\n\t\tret = udf_current_aext(inode, epos, eloc, elen,\n\t\t\t\t       etype, inc);\n\t\tif (ret <= 0)\n\t\t\treturn ret;\n\t\tif (*etype != (EXT_NEXT_EXTENT_ALLOCDESCS >> 30))\n\t\t\treturn ret;\n\n\t\tif (++indirections > UDF_MAX_INDIR_EXTS) {\n\t\t\tudf_err(inode->i_sb,\n\t\t\t\t\"too many indirect extents in inode %llu\\n\",\n\t\t\t\tinode->i_ino);\n\t\t\treturn -EFSCORRUPTED;\n\t\t}\n\n\t\tepos->block = *eloc;\n\t\tepos->offset = sizeof(struct allocExtDesc);\n\t\tbrelse(epos->bh);\n\t\tblock = udf_get_lb_pblock(inode->i_sb, &epos->block, 0);\n\t\tepos->bh = sb_bread(inode->i_sb, block);\n\t\tif (!epos->bh) {\n\t\t\tudf_debug(\"reading block %u failed!\\n\", block);\n\t\t\treturn -EIO;\n\t\t}\n\t}\n}\n\n/*\n * Returns 1 on success, -errno on error, 0 on hit EOF.\n */\nint udf_current_aext(struct inode *inode, struct exten